module test (
	input  logic clock,        
	input  logic reset,
	input  logic [0:0] A,
	input  logic [1:0] B,
	input  logic [2:0] C,
	input  logic [15:0] din,
	output logic [15:0] dout
);
	logic [15:0] mem [0:1][0:3][0:5];

	always @(posedge clock) begin
		if (reset) begin
			for (int I = 0; I < 2; I++)
			for (int K = 0; K < 4; K++)
				mem[I][K] <= '{default:0};
		end else begin
			dout <= mem[A][B][C];
			mem[A][B][C] <= din;
		end
	end
endmodule
